import React, { useState } from 'react';
import { View, TextInput, Button } from 'react-native';

const App = () => {
  const [authCode, setAuthCode] = useState('');
  const [token, setToken] = useState('');

  const handleLogin = async () => {
    try {
      const clientId = 'mobile_app_client_123';
      const clientSecret = 'secret_abc123xyz456';
      const grantType = 'authorization_code';

      const response = await fetch('https://your-auth-server.com/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: `grant_type=${grantType}&code=${authCode}&client_id=${clientId}&client_secret=${clientSecret}`,
      });

      const data = await response.json();
      setToken(data.access_token);
    } catch (error) {
      console.error('Error fetching token:', error);
    }
  };

  return (
    <View>
      <TextInput
        placeholder="Enter Authorization Code"
        value={authCode}
        onChangeText={setAuthCode}
      />
      <Button title="Login" onPress={handleLogin} />
      {token ? <Text>Access Token: {token}</Text> : null}
    </View>
  );
};

export default App;